import{_ as i,o as t,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const l="/images/uebung093.jpg",p=JSON.parse('{"title":"Übung Lektion 54","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung54.md","filePath":"lektionen/uebung54.md"}'),s={name:"lektionen/uebung54.md"};function a(o,e,g,u,d,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-54" tabindex="-1">Übung Lektion 54 <a class="header-anchor" href="#ubung-lektion-54" aria-label="Permalink to &quot;Übung Lektion 54&quot;">​</a></h1><p><em>Erstmals hier publiziert:</em> 2009-03-11</p><p>Falls Sie die diakritischen Zeichen nicht dargestellt bekommen, installieren Sie eine Schrift mit Diakritika wie z.B. Tahoma.</p><p>Übersetzen Sie schriftlich folgende Formen und bilden Sie die entsprechenden Aoristformen:</p><ol><li>यन्ति sie gehen - अगुः</li><li>पिबामि ich trinke - अपाम्</li><li>ददौ ich habe / er hat gegeben - अदाम् । अदात्</li><li>बभूव ich / er / ihr war / wart - अभूवम् । अभूत् । अभूत</li><li>दधति sie setzen - अधुः</li><li>ऐम wir gingen - अगाम</li><li>पपिथ du hast getrunken / du hast geschützt - अपाः (nur zu पा 1 &quot;trinken&quot;)</li><li>तिष्ठति er steht - अस्थात्</li><li>इयेथ du bist gegangen - अगाः</li><li>पप ihr habt getrunken - अपात</li><li>एष्यथ ihr werdet gehen - अगात</li><li>तस्थुः sie standen - अस्थुः</li><li>अधत्त ihr setztet - अधात</li><li>अददाः du gabst - अदाः</li><li>अभवन् sie waren - अभूवन्</li><li>ददिम wir haben gegeben - अदाम</li><li>भिद्यते es wird gespalten - अभेदि</li><li>उद्यते es wird gesagt - अवादि</li><li>स्तूयते er wird gelobt - अस्तावि</li><li>कृष्यते es wird gezogen / gepflügt - अकर्षि</li><li>जायते (Pass.) er wird geboren - अजनि</li><li>गीयते es wird gesungen - अगायि</li><li>गम्यते es wird gegangen -अगामि</li></ol><p><img src="'+l+'" alt=""><br> Abb.: अगायि ॥<br> Darjeeling - দার্জিলিং<br> [Bildquelle: judepics. -- <a href="http://www.flickr.com/photos/judepics/2955447474/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/judepics/2955447474/</a>. -- Zugriff am 2009-03-11. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p>',7)])])}const m=i(s,[["render",a]]);export{p as __pageData,m as default};
